// Parse provider response from LINE message
const message = items[0].json.events[0].message.text.toUpperCase();
const bookingId = message.match(/BK\d+/)?.[0];
const bookingData = $input.first().json;

let response = {
  bookingId: bookingId,
  providerId: items[0].json.events[0].source.userId,
  messageText: message,
  timestamp: new Date().toISOString()
};

if (message.includes('CONFIRM')) {
  response.status = 'confirmed';
  response.action = 'confirm';
  // Provider will send pickup time in next message
  response.needsPickupTime = true;

} else if (message.includes('CANCEL') || message.includes('FULLY BOOKED')) {
  response.status = 'rejected';
  response.reason = 'Fully booked';
  response.action = 'cancel';

} else if (message.includes('ALTERNATIVE')) {
  response.status = 'alternative_location_requested';
  response.action = 'alternative_location';
  response.needsAlternativeLocation = true;

} else if (message.includes('PICKUP TIME:')) {
  // Parse pickup time range
  const timeMatch = message.match(/PICKUP TIME:\s*(.+)/i);
  response.status = 'pickup_time_set';
  response.pickupTime = timeMatch ? timeMatch[1].trim() : 'TBD';
  response.action = 'set_pickup_time';

} else if (message.includes('ALT LOCATION:')) {
  // Parse alternative location
  const locationMatch = message.match(/ALT LOCATION:\s*(.+)/i);
  response.status = 'alternative_location_set';
  response.alternativeLocation = locationMatch ? locationMatch[1].trim() : null;
  response.action = 'set_alternative_location';

} else {
  response.status = 'unclear';
  response.action = 'unclear';
}

return [{ json: { ...bookingData, providerResponse: response } }];

// Generate payment links for all payment methods
const booking = items[0].json;
const amount = booking.totalAmount;
const currency = booking.currency;
const bookingId = booking.bookingId;

// Payment link generators
const paymentLinks = {
  // Cash on Tour - no link needed
  cashOnTour: {
    method: 'Cash on Tour (COT)',
    description: 'Pay cash to the driver at tour start',
    link: null,
    instructions: 'Please have exact change ready. Our driver will provide a receipt.'
  },

  // Thai Bank Transfer
  thaiBank: {
    method: 'Thai Bank Transfer',
    description: 'Transfer to our Thai bank account',
    link: null,
    instructions: `Bank: ${process.env.THAI_BANK_NAME || 'Bangkok Bank'}\nAccount Name: ${process.env.THAI_BANK_ACCOUNT_NAME}\nAccount Number: ${process.env.THAI_BANK_ACCOUNT_NUMBER}\nAmount: ${currency} ${amount}\nReference: ${bookingId}`
  },

  // QR Code Payment (PromptPay)
  qrCode: {
    method: 'QR Code (PromptPay)',
    description: 'Scan QR code to pay via Thai banking app',
    link: `https://promptpay.io/${process.env.PROMPTPAY_ID}/${amount}`,
    qrCodeUrl: `https://promptpay.io/${process.env.PROMPTPAY_ID}/${amount}.png`,
    instructions: 'Scan the QR code with your Thai banking app to complete payment'
  },

  // PayPal
  paypal: {
    method: 'PayPal',
    description: 'Pay securely with PayPal',
    link: `https://www.paypal.com/paypalme/${process.env.PAYPAL_USERNAME}/${amount}${currency}`,
    instructions: 'Click the link to pay with your PayPal account or credit card'
  },

  // Stripe Payment Link
  stripe: {
    method: 'Credit/Debit Card (Stripe)',
    description: 'Pay with credit or debit card',
    link: `${process.env.STRIPE_PAYMENT_LINK_BASE}?client_reference_id=${bookingId}&amount=${amount * 100}`,
    instructions: 'Secure payment via Stripe. All major cards accepted.'
  },

  // Wise (TransferWise)
  wise: {
    method: 'Wise (TransferWise)',
    description: 'International transfer with low fees',
    link: null,
    instructions: `Transfer to our Wise account:\nEmail: ${process.env.WISE_EMAIL}\nAmount: ${currency} ${amount}\nReference: ${bookingId}`
  },

  // Revolut
  revolut: {
    method: 'Revolut',
    description: 'Pay via Revolut',
    link: `https://revolut.me/${process.env.REVOLUT_USERNAME}/${amount}`,
    instructions: 'Click to pay via Revolut. Add reference: ' + bookingId
  }
};

return [{
  json: {
    ...booking,
    paymentLinks: paymentLinks,
    paymentLinkGenerated: true,
    paymentLinkGeneratedAt: new Date().toISOString()
  }
}];

