parameters.functionCode:
// Check if there are more providers to try
const data = items[0].json;
const currentIndex = data.currentProviderIndex;
const providers = data.providers;

if (currentIndex + 1 < providers.length) {
  return [{
    json: {
      ...data,
      currentProviderIndex: currentIndex + 1,
      currentProvider: providers[currentIndex + 1],
      tryNextProvider: true
    }
  }];
} else {
  return [{
    json: {
      ...data,
      tryNextProvider: false,
      allProvidersBooked: true
    }
  }];
}
